constructor (externalSchemas, options) {
  // This instance of Ajv is private
  // it should not be customized or used
  if (options.mode === 'JTD') {
    this.ajv = new AjvJTD(Object.assign({}, defaultAjvOptions, options.customOptions))
  } else {
    this.ajv = new Ajv(Object.assign({}, defaultAjvOptions, options.customOptions))
  }

  let addFormatPlugin = true
  if (options.plugins && options.plugins.length > 0) {
    for (const plugin of options.plugins) {
      if (Array.isArray(plugin)) {
        addFormatPlugin = addFormatPlugin && plugin[0].name !== 'formatsPlugin'
        plugin[0](this.ajv, plugin[1])
      } else {
        addFormatPlugin = addFormatPlugin && plugin.name !== 'formatsPlugin'
        plugin(this.ajv)
      }
    }
  }

  if (addFormatPlugin) {
    require('ajv-formats')(this.ajv)
  }

  options.onCreate?.(this.ajv)

  const sourceSchemas = Object.values(externalSchemas)
  for (const extSchema of sourceSchemas) {
    this.ajv.addSchema(extSchema)
  }
}

function (pluginFn, opts, isAfter) {
  if (isBundledOrTypescriptPlugin(pluginFn)) {
    pluginFn = pluginFn.default
  }
  validatePlugin(pluginFn)
  opts = opts || {}

  if (this.booted) {
    throw new AVV_ERR_ROOT_PLG_BOOTED()
  }

  // we always add plugins to load at the current element
  const current = this._current[0]

  let timeout = this._opts.timeout

  if (!current.loaded && current.timeout > 0) {
    const delta = Date.now() - current.startTime
    // We need to decrease it by 3ms to make sure the internal timeout
    // is triggered earlier than the parent
    timeout = current.timeout - (delta + 3)
  }

  const plugin = new Plugin(fastq(this, this._loadPluginNextTick, 1), pluginFn, opts, isAfter, timeout)
  this._trackPluginLoading(plugin)

  if (current.loaded) {
    throw new Error(plugin.name, current.name)
  }

  // we add the plugin to be loaded at the end of the current queue
  current.enqueue(plugin, (err) => { err && (this._error = err) })

  return plugin
}

function (plugin, callback) {
  const instance = this
  if (isPromiseLike(plugin.func)) {
    plugin.func.then((fn) => {
      if (typeof fn.default === 'function') {
        fn = fn.default
      }
      plugin.func = fn
      this._loadPlugin(plugin, callback)
    }, callback)
    return
  }

  const last = instance._current[0]

  // place the plugin at the top of _current
  instance._current.unshift(plugin)

  if (instance._error && !plugin.isAfter) {
    debug('skipping loading of plugin as instance errored and it is not an after', plugin.name)
    process.nextTick(execCallback)
    return
  }

  let server = last?.server || instance._server

  if (!plugin.isAfter) {
    // Skip override for after
    try {
      server = instance.override(server, plugin.func, plugin.options)
    } catch (overrideErr) {
      debug('override errored', plugin.name)
      return execCallback(overrideErr)
    }
  }

  plugin.exec(server, execCallback)

  function execCallback (err) {
    plugin.finish(err, (err) => {
      instance._current.shift()
      callback(err)
    })
  }
}

async function doMigration (): Promise<void> {
  const connection = await mysql.createConnection({
    multipleStatements: true,
    host: process.env.MYSQL_HOST,
    port: Number(process.env.MYSQL_PORT),
    database: process.env.MYSQL_DATABASE,
    user: process.env.MYSQL_USER,
    password: process.env.MYSQL_PASSWORD
  })

  try {
    const migrationDir = path.join(import.meta.dirname, '../migrations')

    if (!fs.existsSync(migrationDir)) {
      throw new Error(
        `Migration directory "${migrationDir}" does not exist. Skipping migrations.`
      )
    }

    const postgrator = new Postgrator({
      migrationPattern: path.join(migrationDir, '*'),
      driver: 'mysql',
      database: process.env.MYSQL_DATABASE,
      execQuery: async (query: string): Promise<PostgratorResult> => {
        const [rows, fields] = await connection.query(query)
        return { rows, fields }
      },
      schemaTable: 'schemaversion'
    })

    await postgrator.migrate()

    console.log('Migration completed!')
  } catch (err) {
    console.error(err)
  } finally {
    await connection.end().catch(err => console.error(err))
  }
}

async function seedUsers (connection: Connection) {
  const users = [
    { username: 'basic', email: 'basic@example.com' },
    { username: 'moderator', email: 'moderator@example.com' },
    { username: 'admin', email: 'admin@example.com' }
  ]
  const hash = await scryptHash('Password123$')

  // The goal here is to create a role hierarchy
  // E.g. an admin should have all the roles
  const rolesAccumulator: number[] = []

  for (const user of users) {
    const [userResult] = await connection.execute(`
      INSERT INTO users (username, email, password)
      VALUES (?, ?, ?)
    `, [user.username, user.email, hash])

    const userId = (userResult as { insertId: number }).insertId

    const [roleResult] = await connection.execute(`
      INSERT INTO roles (name)
      VALUES (?)
    `, [user.username])

    const newRoleId = (roleResult as { insertId: number }).insertId

    rolesAccumulator.push(newRoleId)

    for (const roleId of rolesAccumulator) {
      await connection.execute(`
        INSERT INTO user_roles (user_id, role_id)
        VALUES (?, ?)
      `, [userId, roleId])
    }
  }

  console.log('Users have been seeded successfully.')
}

async function () {
  const branches = await git.branch()
  const currentBranch = branches.branches[branches.current]

  let featureBranch = null
  let mainBranch = null

  if (process.argv[2] === '--ci') {
    featureBranch = currentBranch.name
    mainBranch = DEFAULT_BRANCH
  } else {
    featureBranch = await selectBranchName('Select the branch you want to compare (feature branch):', branches.all)
    mainBranch = await selectBranchName('Select the branch you want to compare with (main branch):', branches.all)
  }

  try {
    const featureBranchResult = await executeCommandOnBranch(COMMAND, featureBranch)
    const mainBranchResult = await executeCommandOnBranch(COMMAND, mainBranch)
    compareResults(featureBranchResult, mainBranchResult)
  } catch (error) {
    console.error('Switch to origin branch due to an error', error.message)
  }

  await git.checkout(currentBranch.commit)
  await git.checkout(currentBranch.name)

  console.log(`${greyColor}Back to ${currentBranch.name} ${currentBranch.commit}${resetColor}`)
}

() => {
  const results = suite.tasks.map(task => ({
    name: task.name,
    hz: task.result.throughput.mean,
    rme: task.result.latency.rme,
    samples: task.result.latency.df + 1
  }))

  const scenarios = {}
  for (const result of results) {
    const [library, scenario] = result.name.split(':').map(s => s.trim())

    if (!scenarios[scenario]) scenarios[scenario] = []
    scenarios[scenario].push({ ...result, library })
  }

  for (const [scenario, tasks] of Object.entries(scenarios)) {
    console.log(`\n--- ${scenario} ---`)
    const sorted = tasks.sort((a, b) => b.hz - a.hz)
    const winner = sorted[0]

    for (const task of sorted) {
      const formattedHz = task.hz.toLocaleString('en-US', { maximumFractionDigits: 0 })
      const formattedRme = task.rme.toFixed(2)
      const isWinner = task === winner
      const prefix = isWinner ? '🏆 ' : '   '

      console.log(`${prefix}${task.library.padEnd(40)} x ${formattedHz.padStart(15)} ops/sec ±${formattedRme}% (${task.samples} runs sampled)`)
    }
  }
}

function buildAllOf (context, location, input) {
  const schema = location.schema

  let mergedSchemaId = context.mergedSchemasIds.get(schema)
  if (mergedSchemaId) {
    const mergedLocation = getMergedLocation(context, mergedSchemaId)
    return buildValue(context, mergedLocation, input)
  }

  mergedSchemaId = `__fjs_merged_${schemaIdCounter++}`
  context.mergedSchemasIds.set(schema, mergedSchemaId)

  const { allOf, ...schemaWithoutAllOf } = location.schema
  const locations = [
    new Location(
      schemaWithoutAllOf,
      location.schemaId,
      location.jsonPointer
    )
  ]

  const allOfsLocation = location.getPropertyLocation('allOf')
  for (let i = 0, allOfLength = allOf.length; i < allOfLength; i++) {
    locations.push(allOfsLocation.getPropertyLocation(i))
  }

  const mergedLocation = mergeLocations(context, mergedSchemaId, locations)
  return buildValue(context, mergedLocation, input)
}

async function loadPlugins ({ pluginTree, options, opts, fastify }) {
  const nodes = []
  const pluginsMeta = {}
  for (const key in pluginTree) {
    const node = {
      ...pluginTree[key],
      pluginsMeta,
      hooksMeta: {}
    }
    nodes.push(node)

    await Promise.all(node.plugins.map(({ file, type, prefix }) => {
      return loadPlugin({ file, type, directoryPrefix: prefix, options: opts, log: fastify.log })
        .then((plugin) => {
          if (plugin) {
            // create route parameters from prefixed folders
            if (options.routeParams && plugin.options.prefix) {
              plugin.options.prefix = replaceRouteParamPattern(plugin.options.prefix)
            }
            node.pluginsMeta[plugin.name] = plugin
          }
        })
        .catch((err) => {
          throw enrichError(err)
        })
    }))

    await Promise.all(node.hooks.map((h) => {
      return loadHook(h, opts)
        .then((hookPlugin) => {
          node.hooksMeta[h.file] = hookPlugin
        })
        .catch((err) => {
          throw enrichError(err)
        })
    }))
  }

  for (const node of nodes) {
    registerNode(node, fastify)
  }
}

function cli (args) {
  const opts = parseArgs(args, {
    options: {
      help: { type: 'boolean' }
    }
  })

  const dir = process.cwd()

  if (opts._.length !== 1) {
    log('error', 'Missing the required file parameter\n')
    return showHelp()
  }

  if (existsSync(path.join(dir, 'README.md'))) {
    log('error', 'a README.md file already exists in target directory')
    process.exit(1)
  }

  const pluginPath = path.join(dir, path.basename(opts._[0], '.js'))

  let plugin
  try {
    plugin = require(pluginPath)
  } catch (err) {
    log('error', 'plugin could not be loaded', err)
    process.exit(1)
  }

  const pluginMeta = plugin[Symbol.for('plugin-meta')]

  if (!pluginMeta) {
    log('error', 'no plugin metadata could be found. Are you sure that you use https://github.com/fastify/fastify-plugin ?')
    process.exit(1)
  }

  const encapsulated = !plugin[Symbol.for('skip-override')]
  const pluginFileName = path.basename(opts._[0])

  generate(dir, { pluginMeta, encapsulated, pluginFileName }).catch(function (err) {
    if (err) {
      log('error', err.message)
      process.exit(1)
    }
  })
}

function generate (dir, template) {
  return new Promise((resolve, reject) => {
    generify(path.join(__dirname, 'templates', template.dir), dir, {}, function (file) {
      log('debug', `generated ${file}`)
    }, function (err) {
      if (err) {
        return reject(err)
      }

      process.chdir(dir)
      execSync('npm init -y')

      log('info', `reading package.json in ${dir}`)
      readFile('package.json', (err, data) => {
        if (err) {
          return reject(err)
        }

        let pkg
        try {
          pkg = JSON.parse(data)
        } catch (err) {
          return reject(err)
        }

        pkg.main = template.main

        pkg.type = template.type

        pkg.scripts = Object.assign(pkg.scripts || {}, template.scripts)

        pkg.dependencies = Object.assign(pkg.dependencies || {}, template.dependencies)

        pkg.devDependencies = Object.assign(pkg.devDependencies || {}, template.devDependencies)

        log('debug', 'edited package.json, saving')
        writeFile('package.json', JSON.stringify(pkg, null, 2), (err) => {
          if (err) {
            return reject(err)
          }

          template.logInstructions(pkg)
          resolve()
        })
      })
    })
  })
}

function createAddFieldnameToVary (fieldname) {
  const headerCache = new FifoCache(1000)

  validateFieldname(fieldname)

  return function (reply) {
    let header = reply.getHeader('Vary')

    if (!header) {
      reply.header('Vary', fieldname)
      return
    }

    if (header === '*') {
      return
    }

    if (fieldname === '*') {
      reply.header('Vary', '*')
      return
    }

    if (Array.isArray(header)) {
      header = header.join(', ')
    }

    if (headerCache.get(header) === undefined) {
      const vals = parse(header)

      if (vals.indexOf('*') !== -1) {
        headerCache.set(header, '*')
      } else if (vals.indexOf(fieldname.toLowerCase()) === -1) {
        headerCache.set(header, header + ', ' + fieldname)
      } else {
        headerCache.set(header, null)
      }
    }
    const cached = headerCache.get(header)
    if (cached !== null) {
      reply.header('Vary', cached)
    }
  }
}

